import{_ as i,o,c as l,ae as a}from"./chunks/framework.C7FLYIpo.js";const g=JSON.parse('{"title":"트랜스크립트 위생","description":"레퍼런스: 프로바이더별 트랜스크립트 정리 및 수정 규칙","frontmatter":{"title":"트랜스크립트 위생","description":"레퍼런스: 프로바이더별 트랜스크립트 정리 및 수정 규칙"},"headers":[],"relativePath":"reference/transcript-hygiene.md","filePath":"reference/transcript-hygiene.md","lastUpdated":null}'),t={name:"reference/transcript-hygiene.md"};function s(n,e,r,c,d,p){return o(),l("div",null,[...e[0]||(e[0]=[a('<h1 id="트랜스크립트-위생-프로바이더-수정" tabindex="-1">트랜스크립트 위생 (프로바이더 수정) <a class="header-anchor" href="#트랜스크립트-위생-프로바이더-수정" aria-label="Permalink to &quot;트랜스크립트 위생 (프로바이더 수정)&quot;">​</a></h1><p>이 문서는 실행 전 (모델 컨텍스트 구성) 트랜스크립트에 적용되는 <strong>프로바이더별 수정</strong>을 설명합니다. 이것은 엄격한 프로바이더 요구 사항을 충족하기 위해 사용되는 <strong>인메모리</strong> 조정입니다. 이 위생 단계는 디스크에 저장된 JSONL 트랜스크립트를 다시 쓰지 <strong>않습니다</strong>. 그러나 세션이 로드되기 전에 잘못된 JSONL 파일을 수정하는 별도의 세션 파일 수정 패스가 유효하지 않은 줄을 삭제하여 파일을 다시 쓸 수 있습니다. 수정이 발생하면 원본 파일이 세션 파일 옆에 백업됩니다.</p><p>범위:</p><ul><li>도구 호출 ID 정리</li><li>도구 호출 입력 검증</li><li>도구 결과 페어링 수정</li><li>턴 검증 / 순서 지정</li><li>사고 서명 정리</li><li>이미지 페이로드 정리</li><li>사용자 입력 출처 태깅 (세션 간 라우팅된 프롬프트)</li></ul><p>트랜스크립트 저장 세부 사항이 필요한 경우 다음을 참조하십시오:</p><ul><li><a href="/openclaw-docs-ko/reference/session-management-compaction">/reference/session-management-compaction</a></li></ul><hr><h2 id="실행-위치" tabindex="-1">실행 위치 <a class="header-anchor" href="#실행-위치" aria-label="Permalink to &quot;실행 위치&quot;">​</a></h2><p>모든 트랜스크립트 위생은 임베디드 러너에 중앙화되어 있습니다:</p><ul><li>정책 선택: <code>src/agents/transcript-policy.ts</code></li><li>정리/수정 적용: <code>src/agents/pi-embedded-runner/google.ts</code>의 <code>sanitizeSessionHistory</code></li></ul><p>정책은 <code>provider</code>, <code>modelApi</code>, <code>modelId</code>를 사용하여 적용할 내용을 결정합니다.</p><p>트랜스크립트 위생과 별도로, 세션 파일은 로드 전에 필요한 경우 수정됩니다:</p><ul><li><code>src/agents/session-file-repair.ts</code>의 <code>repairSessionFileIfNeeded</code></li><li><code>run/attempt.ts</code> 및 <code>compact.ts</code> (임베디드 러너)에서 호출됨</li></ul><hr><h2 id="전역-규칙-이미지-정리" tabindex="-1">전역 규칙: 이미지 정리 <a class="header-anchor" href="#전역-규칙-이미지-정리" aria-label="Permalink to &quot;전역 규칙: 이미지 정리&quot;">​</a></h2><p>이미지 페이로드는 크기 제한으로 인한 프로바이더 측 거부를 방지하기 위해 항상 정리됩니다 (과도한 base64 이미지 다운스케일/재압축).</p><p>이것은 또한 비전 가능 모델에 대한 이미지 기반 토큰 압박을 제어하는 데 도움이 됩니다. 낮은 최대 크기는 일반적으로 토큰 사용량을 줄입니다. 높은 크기는 세부 사항을 보존합니다.</p><p>구현:</p><ul><li><code>src/agents/pi-embedded-helpers/images.ts</code>의 <code>sanitizeSessionMessagesImages</code></li><li><code>src/agents/tool-images.ts</code>의 <code>sanitizeContentBlocksImages</code></li><li>최대 이미지 면은 <code>agents.defaults.imageMaxDimensionPx</code> (기본값: <code>1200</code>)로 구성 가능합니다.</li></ul><hr><h2 id="전역-규칙-잘못된-도구-호출" tabindex="-1">전역 규칙: 잘못된 도구 호출 <a class="header-anchor" href="#전역-규칙-잘못된-도구-호출" aria-label="Permalink to &quot;전역 규칙: 잘못된 도구 호출&quot;">​</a></h2><p><code>input</code>과 <code>arguments</code> 모두 없는 어시스턴트 도구 호출 블록은 모델 컨텍스트가 구성되기 전에 삭제됩니다. 이는 부분적으로 지속된 도구 호출 (예: 속도 제한 실패 후)로 인한 프로바이더 거부를 방지합니다.</p><p>구현:</p><ul><li><code>src/agents/session-transcript-repair.ts</code>의 <code>sanitizeToolCallInputs</code></li><li><code>src/agents/pi-embedded-runner/google.ts</code>의 <code>sanitizeSessionHistory</code>에서 적용됨</li></ul><hr><h2 id="전역-규칙-세션-간-입력-출처" tabindex="-1">전역 규칙: 세션 간 입력 출처 <a class="header-anchor" href="#전역-규칙-세션-간-입력-출처" aria-label="Permalink to &quot;전역 규칙: 세션 간 입력 출처&quot;">​</a></h2><p>에이전트가 <code>sessions_send</code>를 통해 다른 세션으로 프롬프트를 보낼 때 (에이전트 간 응답/알림 단계 포함), OpenClaw는 생성된 사용자 턴을 다음과 함께 지속합니다:</p><ul><li><code>message.provenance.kind = &quot;inter_session&quot;</code></li></ul><p>이 메타데이터는 트랜스크립트 추가 시 작성되며 역할을 변경하지 않습니다 (<code>role: &quot;user&quot;</code>는 프로바이더 호환성을 위해 유지됨). 트랜스크립트 리더는 이를 사용하여 라우팅된 내부 프롬프트를 최종 사용자 작성 지침으로 취급하는 것을 피할 수 있습니다.</p><p>컨텍스트 재구성 중에 OpenClaw는 인메모리에서 해당 사용자 턴 앞에 짧은 <code>[Inter-session message]</code> 마커를 추가하여 모델이 외부 최종 사용자 지침과 구별할 수 있도록 합니다.</p><hr><h2 id="프로바이더-매트릭스-현재-동작" tabindex="-1">프로바이더 매트릭스 (현재 동작) <a class="header-anchor" href="#프로바이더-매트릭스-현재-동작" aria-label="Permalink to &quot;프로바이더 매트릭스 (현재 동작)&quot;">​</a></h2><p><strong>OpenAI / OpenAI Codex</strong></p><ul><li>이미지 정리만.</li><li>OpenAI Responses/Codex 트랜스크립트에 대해 고아 추론 서명 (뒤따르는 콘텐츠 블록 없이 독립적인 추론 항목) 삭제.</li><li>도구 호출 ID 정리 없음.</li><li>도구 결과 페어링 수정 없음.</li><li>턴 검증 또는 재순서화 없음.</li><li>합성 도구 결과 없음.</li><li>사고 서명 제거 없음.</li></ul><p><strong>Google (Generative AI / Gemini CLI / Antigravity)</strong></p><ul><li>도구 호출 ID 정리: 엄격한 영숫자.</li><li>도구 결과 페어링 수정 및 합성 도구 결과.</li><li>턴 검증 (Gemini 스타일 턴 교대).</li><li>Google 턴 순서 수정 (기록이 어시스턴트로 시작하면 작은 사용자 부트스트랩 추가).</li><li>Antigravity Claude: 사고 서명 정규화; 서명되지 않은 사고 블록 삭제.</li></ul><p><strong>Anthropic / Minimax (Anthropic 호환)</strong></p><ul><li>도구 결과 페어링 수정 및 합성 도구 결과.</li><li>턴 검증 (엄격한 교대를 충족하기 위해 연속 사용자 턴 병합).</li></ul><p><strong>Mistral (모델 ID 기반 감지 포함)</strong></p><ul><li>도구 호출 ID 정리: strict9 (영숫자 길이 9).</li></ul><p><strong>OpenRouter Gemini</strong></p><ul><li>사고 서명 정리: 비 base64 <code>thought_signature</code> 값 제거 (base64 유지).</li></ul><p><strong>그 외 모든 것</strong></p><ul><li>이미지 정리만.</li></ul><hr><h2 id="이전-동작-2026-1-22-이전" tabindex="-1">이전 동작 (2026.1.22 이전) <a class="header-anchor" href="#이전-동작-2026-1-22-이전" aria-label="Permalink to &quot;이전 동작 (2026.1.22 이전)&quot;">​</a></h2><p>2026.1.22 릴리스 이전에 OpenClaw는 여러 레이어의 트랜스크립트 위생을 적용했습니다:</p><ul><li><strong>트랜스크립트 정리 확장</strong>이 모든 컨텍스트 빌드에서 실행되며: <ul><li>도구 사용/결과 페어링 수정.</li><li>도구 호출 ID 정리 (<code>_</code>/<code>-</code>를 보존하는 비엄격 모드 포함).</li></ul></li><li>러너도 프로바이더별 정리를 수행하여 작업이 중복되었습니다.</li><li>다음을 포함한 정책 외부에서 추가 변형이 발생했습니다: <ul><li>지속 전에 어시스턴트 텍스트에서 <code>&amp;lt;final&amp;gt;</code> 태그 제거.</li><li>빈 어시스턴트 오류 턴 삭제.</li><li>도구 호출 후 어시스턴트 콘텐츠 트리밍.</li></ul></li></ul><p>이 복잡성은 크로스 프로바이더 회귀 (특히 <code>openai-responses</code> <code>call_id|fc_id</code> 페어링)를 일으켰습니다. 2026.1.22 정리는 확장을 제거하고, 러너에 로직을 중앙화하고, OpenAI를 이미지 정리 외에는 <strong>변경 없음</strong>으로 만들었습니다.</p>',49)])])}const h=i(t,[["render",s]]);export{g as __pageData,h as default};
